function artifact = makeTestArtifact(artifactType)
%MAKETESTARTIFACT Construct a complete valid artifact for unit tests.
if nargin < 1
    artifactType = 'solution';
end
decisionSpec = lmz.schema.VariableSpec('x', 'Unit', 'm', 'Scale', 2);
parameterSpec = lmz.schema.VariableSpec('mass', 'Unit', 'kg', ...
    'Topology', 'positive', 'LowerBound', 0, 'DefaultValue', 1);
artifact = struct( ...
    'schemaVersion', '1.0.0', ...
    'artifactType', artifactType, ...
    'modelId', 'slip_biped', ...
    'modelVersion', '1.0.0', ...
    'problemId', 'test_problem', ...
    'problemVersion', '1.0.0', ...
    'decisionSchema', lmz.schema.VariableSchema(decisionSpec).toStruct(), ...
    'parameterSchema', lmz.schema.VariableSchema(parameterSpec).toStruct(), ...
    'decisionValues', 3, ...
    'parameterValues', 1, ...
    'diagnostics', struct(), ...
    'lineage', struct(), ...
    'randomSeed', 42, ...
    'sourceCommitSHAs', struct(), ...
    'createdAt', '2026-07-19T00:00:00Z', ...
    'matlabVersion', version, ...
    'codeVersion', 'test');
end
